<link href="https://cdn.quilljs.com/1.3.6/quill.snow.css" rel="stylesheet" />
<link href="https://unpkg.com/quill-image-uploader@1.2.3/dist/quill.imageUploader.min.css" rel="stylesheet" />
        <div class="section" id="assignments">
            <div class="d-flex justify-content-between align-items-center mb-20">
                <h1></h1>
                <button class="btn btn-primary" onclick="OpenaddAssignmentModal()">
                    <i class="fas fa-plus"></i> Yeni Tapşırıq
                </button>
            </div>
            <div class="card mb-20">
                <div class="card-header">
                    <h3 class="card-title">Tapşırıqlar Siyahısı</h3>
                </div>
                <div class="m-2 d-flex gap-10">
                    <select class="mb-2 form-select" id="assignmentTopicFilter" onchange="filterAssignments()">
                        <option value="">Bütün Mövzular</option>
                    </select>
                    <select class="mb-2 form-select" id="assignmentGroupFilter" onchange="filterAssignments()">
                        <option value="">Bütün Qruplar</option>
                    </select>
                </div>
                <div class="m-2 d-flex gap-10">
                    <input type="text" class="form-control" id="assignmentSearchInput" placeholder="Axtar..." oninput="filterAssignments()">
                </div>
                <div class="card-body">
                    <div class="table-container">
                        <table class="table" id="assignmentsTable">
                            <thead>
                                <tr>
                                    <th>Tapşırıq</th>
                                    <th>Mövzu</th>
                                    <th>Qrup</th>
                                    <th>Təsvir</th>
                                    <th>Son Tarix</th>
                                    <th>Əməliyyatlar</th>
                                </tr>
                            </thead>
                            <tbody id="assignmentsTableBody">
                            </tbody>
                        </table>
                    </div>
                </div>
            </div>
        </div>
        <script src="https://cdn.quilljs.com/1.3.6/quill.min.js"></script>
        <script src="https://unpkg.com/quill-image-uploader@1.2.3/dist/quill.imageUploader.min.js"></script>

<script>
function OpenaddAssignmentModal(){if(document.getElementById('addAssignmentModal'))return;const modal=document.createElement('div');modal.id='addAssignmentModal';modal.style.cssText=`position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.74);display:flex;justify-content:center;align-items:center;z-index:9999;font-family:'Segoe UI',sans-serif;`;modal.innerHTML=`<div style="background:#fff;border-radius:12px;padding:25px;width:90%;max-width:700px;max-height:90vh;overflow-y:auto;position:relative;box-shadow:0 10px 30px rgba(0,0,0,0.2);"><h2 style="margin:0 0 20px;font-weight:600;">📘 Yeni Tapşırıq Əlavə Et</h2><form id="addAssignmentForm"><div style="margin-bottom:15px;"><label style="font-weight:500;">Tapşırıq Adı</label><input type="text" name="assignmentName" required style="width:100%;padding:10px;margin-top:5px;border:1px solid #ccc;border-radius:6px;"></div><div style="margin-bottom:15px;"><label style="font-weight:500;">Mövzu</label><select name="assignmentTopic" id="modalAssignmentTopic" required style="width:100%;padding:10px;margin-top:5px;border:1px solid #ccc;border-radius:6px;"><option value="">Mövzu seçin</option></select></div><div style="margin-bottom:15px;"><label style="font-weight:500;">Qrup</label><select name="assignmentGroup" id="modalAssignmentGroup" required style="width:100%;padding:10px;margin-top:5px;border:1px solid #ccc;border-radius:6px;"><option value="">Qrup seçin</option></select></div><div style="margin-bottom:15px;"><label style="font-weight:500;">Təsvir</label><div id="assignmentDescriptionEditor" style="min-height:150px;border:1px solid #ccc;border-radius:6px;background:white;"></div><textarea name="assignmentDescription" id="assignmentDescription" style="display:none;"></textarea></div><div style="margin-bottom:15px;"><label style="font-weight:500;">Son Tarix</label><input type="date" name="assignmentDeadline" required style="width:100%;padding:10px;margin-top:5px;border:1px solid #ccc;border-radius:6px;"></div><div style="margin-bottom:20px;"><label style="font-weight:500;">Fayllar</label><input type="file" name="assignmentFiles[]" multiple id="assignmentFiles" style="width:100%;padding:10px;margin-top:5px;border:1px solid #ccc;border-radius:6px;"><div id="fileNames" style="margin-top:10px;font-size:14px;color:#555;"></div><small style="color:#555;">PDF, DOC, DOCX, TXT, JPG, JPEG, PNG (max 5MB)</small></div><div style="display:flex;gap:10px;justify-content:flex-end;"><button type="button" onclick="closeAddAssignmentModal()" style="background:#6c757d;color:white;padding:10px 20px;border:none;border-radius:6px;cursor:pointer;">Ləğv et</button><button type="submit" style="background:rgba(23,63,105,0.98);color:white;padding:10px 20px;border:none;border-radius:6px;font-weight:600;cursor:pointer;">Yadda Saxla</button></div></form></div>`;document.body.appendChild(modal);modal.addEventListener('click',function(e){if(e.target===modal)closeAddAssignmentModal();});fetch('movzular/tapsiriq/get_topics_and_groups.php').then(response=>response.json()).then(data=>{if(data.status==='success'){const topicSelect=document.getElementById('modalAssignmentTopic');if(data.movzular&&data.movzular.length>0){data.movzular.forEach(movzu=>{const option=document.createElement('option');option.value=movzu.id;option.textContent=movzu.movzu_adi;topicSelect.appendChild(option);});}else{topicSelect.innerHTML='<option value="">Mövzu yoxdur</option>';}const groupSelect=document.getElementById('modalAssignmentGroup');if(data.qruplar&&data.qruplar.length>0){data.qruplar.forEach(qrup=>{const option=document.createElement('option');option.value=qrup.id;option.textContent=qrup.qrup_adi;groupSelect.appendChild(option);});}else{groupSelect.innerHTML='<option value="">Qrup yoxdur</option>';}}else{alert('Məlumatlar yüklənərkən xəta baş verdi: '+(data.message||''));}}).catch(error=>{console.error('Error:',error);alert('Məlumatlar yüklənərkən xəta baş verdi!');});const fileInput=document.getElementById('assignmentFiles');const fileNamesDiv=document.getElementById('fileNames');fileInput.addEventListener('change',function(){const files=fileInput.files;fileNamesDiv.innerHTML='';for(let i=0;i<files.length;i++){fileNamesDiv.innerHTML+=`<p style="margin:5px 0;">${files[i].name}</p>`;}});if(typeof Quill!=='undefined'){const quill=new Quill('#assignmentDescriptionEditor',{theme:'snow',placeholder:'Təsviri daxil edin...',modules:{toolbar:[[{header:[1,2,3,false]}],['bold','italic','underline','strike'],[{list:'ordered'},{list:'bullet'}],['link','image'],['clean']]}});const form=document.getElementById('addAssignmentForm');form.addEventListener('submit',function(e){e.preventDefault();document.getElementById('assignmentDescription').value=quill.root.innerHTML;const formData=new FormData(form);fetch('movzular/tapsiriq/save_assignment.php',{method:'POST',body:formData}).then(response=>response.json()).then(data=>{if(data.status==='success'){alert('Tapşırıq uğurla əlavə edildi!');closeAddAssignmentModal();location.reload();}else{alert('Xəta: '+(data.message||'Tapşırıq əlavə edilərkən xəta baş verdi!'));}}).catch(error=>{console.error('Error:',error);alert('Xəta baş verdi! Xahiş edirik yenidən cəhd edin.');});});}}
function closeAddAssignmentModal(){const modal=document.getElementById('addAssignmentModal');if(modal)modal.remove();}
document.addEventListener("DOMContentLoaded",()=>{let allAssignments=[];let allTopics=[];let allGroups=[];let editQuillEditor;let removedFiles=[];loadAssignmentsData();loadTopicsAndGroups();const today=new Date().toISOString().split("T")[0];const deadlineInput=document.getElementById("assignmentDeadline");if(deadlineInput){deadlineInput.min=today;}function loadAssignmentsData(){fetch("movzular/tapsiriq/get_assignments.php").then((response)=>response.json()).then((data)=>{if(data.status==="success"){allAssignments=data.assignments;allTopics=data.movzular;allGroups=data.qruplar;populateFilterDropdowns();displayAssignments(allAssignments);}else{console.error("Error loading assignments:",data.message);alert("Tapşırıqlar yüklənmədi. Xəta baş verdi: "+data.message);}}).catch((error)=>{console.error("Error fetching assignments:",error);alert("Tapşırıqlar yüklənmədi. Xəta baş verdi.");});}function loadTopicsAndGroups(){fetch("movzular/tapsiriq/get_topics_and_groups.php").then((response)=>{if(!response.ok){throw new Error(`HTTP error! status: ${response.status}`);}return response.json();}).then((data)=>{if(data.status==="success"){const topicDropdown=document.getElementById("assignmentTopic");if(topicDropdown){while(topicDropdown.options.length>1){topicDropdown.remove(1);}if(data.movzular&&data.movzular.length===0){const option=document.createElement("option");option.value="";option.textContent="Mövzu yoxdur";option.disabled=true;topicDropdown.appendChild(option);}else if(data.movzular){data.movzular.forEach((movzu)=>{const option=document.createElement("option");option.value=movzu.id;option.textContent=movzu.movzu_adi;topicDropdown.appendChild(option);});}}const groupDropdown=document.getElementById("assignmentGroup");if(groupDropdown){while(groupDropdown.options.length>1){groupDropdown.remove(1);}if(data.qruplar&&data.qruplar.length===0){const option=document.createElement("option");option.value="";option.textContent="Qrup yoxdur";option.disabled=true;groupDropdown.appendChild(option);}else if(data.qruplar){data.qruplar.forEach((qrup)=>{const option=document.createElement("option");option.value=qrup.id;option.textContent=qrup.qrup_adi;groupDropdown.appendChild(option);});}}}else{console.error("Error loading topics and groups:",data.message);}}).catch((error)=>{console.error("Error fetching topics and groups:",error);});}function populateFilterDropdowns(){const topicFilter=document.getElementById("assignmentTopicFilter");if(topicFilter){while(topicFilter.options.length>1){topicFilter.remove(1);}allTopics.forEach((topic)=>{const option=document.createElement("option");option.value=topic.movzu_adi;option.textContent=topic.movzu_adi;topicFilter.appendChild(option);});}const groupFilter=document.getElementById("assignmentGroupFilter");if(groupFilter){while(groupFilter.options.length>1){groupFilter.remove(1);}allGroups.forEach((group)=>{const option=document.createElement("option");option.value=group.qrup_adi;option.textContent=group.qrup_adi;groupFilter.appendChild(option);});}}function displayAssignments(assignments){const tbody=document.getElementById("assignmentsTableBody");if(!tbody)return;tbody.innerHTML="";if(!assignments||assignments.length===0){const noDataRow=document.createElement("tr");noDataRow.innerHTML='<td colspan="6" class="text-center">Tapşırıq tapılmadı</td>';tbody.appendChild(noDataRow);return;}const formatDate=(dateString)=>{if(!dateString)return"N/A";return dateString.split(" ")[0];};assignments.forEach((assignment)=>{const truncateText=(text,maxLength=50)=>{if(!text)return"N/A";const strippedText=text.replace(/<[^>]*>/g,"");if(strippedText.length<=maxLength)return strippedText;return strippedText.substring(0,maxLength)+"...";};const row=document.createElement("tr");row.innerHTML=`<td>${assignment.ad||"N/A"}</td><td>${assignment.movzu_adi||"N/A"}</td><td>${assignment.qrup_adi||"N/A"}</td><td>${truncateText(assignment.tesvir)}</td><td>${formatDate(assignment.son_tarix)}</td><td><div class="action-buttons"><button class="btn btn-sm btn-info" onclick="viewAssignment(${assignment.id})" title="Bax"><i class="fas fa-eye"></i></button><button class="btn btn-sm btn-primary" onclick="editAssignment(${assignment.id})" title="Redaktə et"><i class="fas fa-edit"></i></button><button class="btn btn-sm btn-danger" onclick="deleteAssignment(${assignment.id})" title="Sil"><i class="fas fa-trash"></i></button></div></td>`;tbody.appendChild(row);});}window.filterAssignments=filterAssignments;window.viewAssignment=viewAssignment;window.editAssignment=editAssignment;window.deleteAssignment=deleteAssignment;window.removeFile=removeFile;function filterAssignments(){const topicFilter=document.getElementById("assignmentTopicFilter").value; const groupFilter=document.getElementById("assignmentGroupFilter").value;const searchTerm=document.getElementById("assignmentSearchInput").value.toLowerCase();const filteredAssignments=allAssignments.filter((assignment)=>{const matchesTopic=!topicFilter||assignment.movzu_adi===topicFilter;const matchesGroup=!groupFilter||assignment.qrup_adi===groupFilter;const matchesSearch=!searchTerm||(assignment.ad&&assignment.ad.toLowerCase().includes(searchTerm))||(assignment.movzu_adi&&assignment.movzu_adi.toLowerCase().includes(searchTerm))||(assignment.qrup_adi&&assignment.qrup_adi.toLowerCase().includes(searchTerm))||(assignment.tesvir&&assignment.tesvir.toLowerCase().includes(searchTerm));return matchesTopic&&matchesGroup&&matchesSearch;});displayAssignments(filteredAssignments);}function viewAssignment(id){fetch(`movzular/tapsiriq/getviewdata.php?id=${id}`).then((response)=>response.json()).then((data)=>{if(data.status==="success"&&data.assignment){const assignment=data.assignment;let modal=document.getElementById("viewAssignmentModal");if(!modal){modal=document.createElement("div");modal.id="viewAssignmentModal";modal.className="modal fade";modal.tabIndex=-1;modal.ariaHidden="true";modal.style.zIndex="1055";document.body.appendChild(modal);}else{modal.className="modal fade";modal.tabIndex=-1;modal.ariaHidden="true";modal.style.zIndex="1055";}let filesHtml="";let showFilesSection=false;if(assignment.fayllar){if(Array.isArray(assignment.fayllar)&&assignment.fayllar.length>0){showFilesSection=true;filesHtml=assignment.fayllar.map((file)=>`<li class="list-group-item"><a href="${file}" target="_blank">${file.split("/").pop()}</a></li>`).join("");}}modal.innerHTML=`<div class="modal-dialog modal-dialog-lg"><div class="modal-content"><div class="modal-header"><h3 class="modal-title">${assignment.ad||"Tapşırıq"}</h3></div><div class="modal-body"><div class="assignment-details"><p><strong>Mövzu:</strong> <span>${assignment.movzu_adi||"N/A"}</span></p><p><strong>Qrup:</strong> <span>${assignment.qrup_adi||"N/A"}</span></p><p><strong>Son Tarix:</strong> <span>${assignment.son_tarix||"N/A"}</span></p><div class="mt-3"><h5>Təsvir:</h5><div class="description-content">${assignment.tesvir||"Təsvir yoxdur"}</div></div><div class="mt-3" id="viewAssignmentFilesContainer" style="display:${showFilesSection?"block":"none"};"><h5>Fayllar:</h5><ul class="list-group" id="viewAssignmentFiles">${filesHtml}</ul></div></div></div><div class="modal-footer"><button type="button" class="btn btn-secondary" data-bs-dismiss="modal">Bağla</button></div></div></div>`;const bsModal=new bootstrap.Modal(modal);bsModal.show();}else{alert("Xəta: "+(data.message||"Tapşırıq tapılmadı"));}}).catch((error)=>{console.error("Error:",error);alert("Xəta baş verdi. Zəhmət olmasa yenidən cəhd edin.");});}function editAssignment(id){removedFiles=[];fetch(`movzular/tapsiriq/getviewdata.php?id=${id}`).then((response)=>response.json()).then((data)=>{if(data.status==="success"&&data.assignment){const assignment=data.assignment;let modal=document.getElementById("editAssignmentModal");if(!modal){modal=document.createElement("div");modal.id="editAssignmentModal";modal.className="modal fade";modal.tabIndex=-1;modal.ariaHidden="true";modal.style.zIndex="1055";document.body.appendChild(modal);}else{modal.className="modal fade";modal.tabIndex=-1;modal.ariaHidden="true";modal.style.zIndex="1055";}modal.innerHTML=`<div class="modal-dialog modal-dialog-lg"><div style='max-height:90vh;overflow-y:auto;' class="modal-content"><div class="modal-header"><h3 class="modal-title">Tapşırıq Dəyişdir</h3></div><div class="modal-body"><form id="editAssignmentForm" enctype="multipart/form-data"><input type="hidden" id="editAssignmentId" name="assignmentId" value="${assignment.id}"><div class="mb-3"><label class="form-label" for="editAssignmentName">Tapşırıq Adı</label><input type="text" class="form-control" id="editAssignmentName" name="assignmentName" value="${assignment.ad||""}" required></div><div class="mb-3"><label class="form-label" for="editAssignmentTopic">Mövzu</label><select class="form-select" id="editAssignmentTopic" name="assignmentTopic" required><option value="">Mövzu seçin</option>${allTopics.map((topic)=>`<option value="${topic.id}" ${topic.id==assignment.movzu?"selected":""}>${topic.movzu_adi}</option>`).join("")}</select></div><div class="mb-3"><label class="form-label" for="editAssignmentGroup">Qrup</label><select class="form-select" id="editAssignmentGroup" name="assignmentGroup" required><option value="">Qrup seçin</option>${allGroups.map((group)=>`<option value="${group.id}" ${group.id==assignment.qrup?"selected":""}>${group.qrup_adi}</option>`).join("")}</select></div><div class="mb-3"><label class="form-label" for="editAssignmentDescriptionEditor">Təsvir</label><div id="editAssignmentDescriptionEditor" style="min-height:150px;border:1px solid #ccc;border-radius:4px;"></div><textarea id="editAssignmentDescription" name="assignmentDescription" style="display:none;">${assignment.tesvir||""}</textarea></div><div class="mb-3"><label class="form-label" for="editAssignmentDeadline">Son Tarix</label><input type="date" class="form-control" id="editAssignmentDeadline" name="assignmentDeadline" value="${assignment.son_tarix||""}" required></div><div class="mb-3"><label class="form-label">Mövcud Fayllar</label><div id="existingFiles" class="mb-2">${Array.isArray(assignment.fayllar)&&assignment.fayllar.length>0?assignment.fayllar.map((file)=>`<div class="file-item" style="margin-bottom:5px;"><a href="${file}" target="_blank">${file.split("/").pop()}</a><button style='margin-left:12px;' type="button" class="btn btn-sm btn-danger" onclick="removeFile('${file}')"><i class="fas fa-times"></i></button></div>`).join(""):"<p>Fayl yoxdur</p>"}</div><input type="hidden" id="removedFiles" name="removedFiles" value="[]"></div><div class="mb-3"><label class="form-label" for="editAssignmentFiles">Yeni Fayllar Əlavə Et</label><input type="file" class="form-control" id="editAssignmentFiles" name="assignmentFiles[]" multiple><small class="form-text text-muted">İcazə verilən fayl növləri: PDF, DOC, DOCX, TXT, JPG, JPEG, PNG (maksimum 5MB)</small></div></form></div><div class="modal-footer"><button type="button" class="btn btn-secondary" data-bs-dismiss="modal">Ləğv et</button><button type="button" class="btn btn-primary" id="saveEditBtn">Yadda Saxla</button></div></div></div>`;const bsModal=new bootstrap.Modal(modal);bsModal.show();editQuillEditor=new Quill("#editAssignmentDescriptionEditor",{theme:"snow",modules:{toolbar:[["bold","italic","underline","strike"],["blockquote","code-block"],[{header:1},{header:2}],[{list:"ordered"},{list:"bullet"}],[{script:"sub"},{script:"super"}],[{indent:"-1"},{indent:"+1"}],[{direction:"rtl"}],[{size:["small",false,"large","huge"]}],[{color:[]},{background:[]}],[{font:[]}],[{align:[]}],["clean"],["link","image"]]},placeholder:"Təsvir yazın..."});editQuillEditor.root.innerHTML=assignment.tesvir||"";document.getElementById("saveEditBtn").addEventListener("click",()=>{const editorContent=editQuillEditor.root.innerHTML;document.getElementById("editAssignmentDescription").value=editorContent;document.getElementById("removedFiles").value=JSON.stringify(removedFiles);const formData=new FormData(document.getElementById("editAssignmentForm"));fetch("movzular/tapsiriq/update_assignment.php",{method:"POST",body:formData}).then((response)=>response.json()).then((data)=>{if(data.status==="success"){bsModal.hide();removedFiles=[];loadAssignmentsData();alert("Tapşırıq uğurla yeniləndi!");}else{alert("Xəta: "+data.message);}}).catch((error)=>{console.error("Error:",error);alert("Xəta baş verdi. Zəhmət olmasa yenidən cəhd edin.");});});}else{alert("Xəta: "+(data.message||"Tapşırıq tapılmadı"));}}).catch((error)=>{console.error("Error:",error);alert("Xəta baş verdi. Zəhmət olmasa yenidən cəhd edin.");});}function deleteAssignment(id){let modal=document.getElementById("deleteConfirmModal");if(!modal){modal=document.createElement("div");modal.id="deleteConfirmModal";modal.className="modal fade";modal.tabIndex=-1;modal.ariaHidden="true";modal.style.zIndex="1055";document.body.appendChild(modal);}else{modal.className="modal fade";modal.tabIndex=-1;modal.ariaHidden="true";modal.style.zIndex="1055";}modal.innerHTML=`<div class="modal-dialog"><div class="modal-content"><div class="modal-header"><h3 class="modal-title">Təsdiq</h3></div><div class="modal-body"><p>Bu tapşırığı silmək istədiyinizə əminsiniz?</p></div><div class="modal-footer"><button type="button" class="btn btn-secondary" data-bs-dismiss="modal">Ləğv et</button><button type="button" class="btn btn-danger" id="confirmDeleteBtn">Sil</button></div></div></div>`;const bsModal=new bootstrap.Modal(modal);bsModal.show();document.getElementById("confirmDeleteBtn").addEventListener("click",function(){this.disabled=true;fetch("movzular/tapsiriq/delete_assignment.php",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({id:id})}).then((response)=>response.json()).then((data)=>{if(data.status==="success"){bsModal.hide();loadAssignmentsData();alert("Tapşırıq uğurla silindi!");}else{alert("Xəta: "+data.message);}}).catch((error)=>{console.error("Error:",error);alert("Xəta baş verdi. Zəhmət olmasa yenidən cəhd edin.");}).finally(()=>{document.getElementById("confirmDeleteBtn").disabled=false;});});}function removeFile(filePath){removedFiles.push(filePath);const fileItem=document.querySelector(`.file-item a[href="${filePath}"]`).parentNode;fileItem.remove();}});
</script>